from urllib.parse import urlencode, urlparse, parse_qs

DEFAULT_REDIRECT_PATH = "/dashboard"


def is_safe_redirect_url(url: str, allowed_hosts=None, allowed_schemes=None) -> bool:
    if not url:
        return False

    allowed_hosts = set(allowed_hosts or set())
    allowed_schemes = set(allowed_schemes or {"http", "https"})

    parsed = urlparse(url)

    if parsed.scheme and parsed.scheme not in allowed_schemes:
        return False

    if parsed.netloc and parsed.netloc not in allowed_hosts:
        return False

    if url.startswith("//"):
        return False

    return True


def build_login_url(
    login_path: str = "/login",
    current_url: str = "/",
    next_param: str = "next",
    allowed_hosts=None,
) -> str:
    if not is_safe_redirect_url(current_url, allowed_hosts=allowed_hosts):
        current_url = DEFAULT_REDIRECT_PATH

    query = urlencode({next_param: current_url})
    separator = "&" if "?" in login_path else "?"
    return f"{login_path}{separator}{query}"


def get_post_login_redirect(
    next_url: str = None,
    fallback_url: str = DEFAULT_REDIRECT_PATH,
    allowed_hosts=None,
) -> str:
    if is_safe_redirect_url(next_url, allowed_hosts=allowed_hosts):
        return next_url
    return fallback_url


def get_next_from_login_url(login_url: str, next_param: str = "next") -> str | None:
    parsed = urlparse(login_url)
    params = parse_qs(parsed.query)
    values = params.get(next_param)
    return values[0] if values else None


def redirect_after_authentication(
    is_authenticated: bool,
    requested_url: str,
    login_path: str = "/login",
    fallback_url: str = DEFAULT_REDIRECT_PATH,
    allowed_hosts=None,
) -> str:
    if not is_authenticated:
        return build_login_url(
            login_path=login_path,
            current_url=requested_url,
            allowed_hosts=allowed_hosts,
        )
    return get_post_login_redirect(
        next_url=requested_url,
        fallback_url=fallback_url,
        allowed_hosts=allowed_hosts,
    )


if __name__ == "__main__":
    requested = "/settings/profile"
    login_redirect = redirect_after_authentication(
        is_authenticated=False,
        requested_url=requested,
    )
